const executions = $input.all().map(item => item.json);

const filtered = executions.map(exec => {
  const runData = exec?.data?.resultData?.runData ?? {};

  const nodes = Object.entries(runData).map(([nodeName, runs]) => {
    const run = runs[0];

    const error = run?.error
      ? {
          message: run.error.message ?? null,
          description: run.error.description ?? null,
          type: run.error.type ?? null,
          context: run.error.context ?? null,
          httpCode: run.error.httpCode ?? null,
        }
      : null;

    return {
      name: nodeName,
      status: run?.executionStatus ?? null,
      index: run?.executionIndex ?? null,
      ...(error && { error }),
      ...(exec.status !== 'success' && { executionMs: run?.executionTime ?? null }),
    };
  });

  nodes.sort((a, b) => a.index - b.index);

  const startedAt = new Date(exec.startedAt);
  const stoppedAt = new Date(exec.stoppedAt);

  const lastNodeName = exec.data?.resultData?.lastNodeExecuted;
  const lastRun = lastNodeName ? runData[lastNodeName]?.[0] : null;

  const output = (() => {
    if (!lastRun) return null;
    if (lastRun.error) {
      return {
        error: {
          message: lastRun.error.message ?? null,
          description: lastRun.error.description ?? null,
          type: lastRun.error.type ?? null,
          context: lastRun.error.context ?? null,
          httpCode: lastRun.error.httpCode ?? null,
        }
      };
    }
    return lastRun?.data?.main?.[0]?.[0]?.json ?? null;
  })();

  const firstNode = Object.values(runData)[0];
  const firstJson = firstNode?.[0]?.data?.main?.[0]?.[0]?.json ?? null;

  return {
    executionId: String(exec.id),
    workflowId: exec.workflowId,
    workflowName: exec.workflowData?.name ?? null,
    status: exec.status,
    mode: exec.mode,
    startedAt: exec.startedAt,
    stoppedAt: exec.stoppedAt,
    durationMs: stoppedAt - startedAt,
    input: firstJson
      ? {
          body: firstJson.body ?? null,
          query: firstJson.query ?? null,
        }
      : null,
    nodes,
    lastNodeExecuted: lastNodeName ?? null,
    output,
  };
});

return filtered.map(item => ({ json: item }));

